import{_ as n,c as t,o as e,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"プランレビュー: AIプランをビジュアルでレビュー | Plannotator","description":"Plannotatorのプランレビュー機能を学びます。ビジュアルインターフェースでAI生成プランをレビューし、アノテーションの追加、承認または却下の方法、ApproveとRequest Changesの違いをマスターします。","frontmatter":{"title":"プランレビュー: AIプランをビジュアルでレビュー | Plannotator","subtitle":"プランレビュー基礎：AIプランをビジュアルでレビュー","description":"Plannotatorのプランレビュー機能を学びます。ビジュアルインターフェースでAI生成プランをレビューし、アノテーションの追加、承認または却下の方法、ApproveとRequest Changesの違いをマスターします。","sidebarTitle":"5分でプランレビューをマスター","tags":["プランレビュー","ビジュアルレビュー","アノテーション","承認","却下","Claude Code","OpenCode"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"ja/backnotprop/plannotator/platforms/plan-review-basics/index.md","filePath":"ja/backnotprop/plannotator/platforms/plan-review-basics/index.md"}'),o={name:"ja/backnotprop/plannotator/platforms/plan-review-basics/index.md"};function l(p,a,i,r,d,c){return e(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="プランレビュー基礎-aiプランをビジュアルでレビュー" tabindex="-1">プランレビュー基礎：AIプランをビジュアルでレビュー <a class="header-anchor" href="#プランレビュー基礎-aiプランをビジュアルでレビュー" aria-label="Permalink to &quot;プランレビュー基礎：AIプランをビジュアルでレビュー&quot;">​</a></h1><h2 id="この章で学べること" tabindex="-1">この章で学べること <a class="header-anchor" href="#この章で学べること" aria-label="Permalink to &quot;この章で学べること&quot;">​</a></h2><ul><li>✅ Plannotatorのビジュアルインターフェースを使ってAI生成プランをレビューする</li><li>✅ プランテキストを選択し、異なるタイプのアノテーション（削除、置換、コメント）を追加する</li><li>✅ プランを承認し、AIに実装を続行させる</li><li>✅ プランを却下し、アノテーションをフィードバックとしてAIに送信する</li><li>✅ アノテーションタイプの使用シナリオと違いを理解する</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p><strong>課題1</strong>：AI生成の実装プランをターミナルで読むと、テキスト量が多く構造が不明瞭で、レビューが大変。</p><p><strong>課題2</strong>：AIにフィードバックを伝えたいとき、「3段落目を削除」「この関数を修正」などテキストで説明するしかなく、コミュニケーションコストが高い上、AIが誤解する可能性もある。</p><p><strong>課題3</strong>：プランの中には修正不要な部分、置換が必要な部分、コメントが必要な部分があるが、これらのフィードバックを構造化するツールがない。</p><p><strong>課題4</strong>：プランを承認したのか、修正が必要なのかをAIに伝える方法がわからない。</p><p><strong>Plannotatorでできること</strong>：</p><ul><li>ビジュアルUIでターミナル閲覧を置き換え、構造を明確化</li><li>テキストを選択するだけでアノテーション（削除、置換、コメント）を追加し、正確なフィードバックが可能</li><li>アノテーションが自動的に構造化データに変換され、AIがあなたの意図を正確に理解</li><li>ワンクリックで承認または却下、AIが即座に応答</li></ul><h2 id="こんなときに使う" tabindex="-1">こんなときに使う <a class="header-anchor" href="#こんなときに使う" aria-label="Permalink to &quot;こんなときに使う&quot;">​</a></h2><p><strong>適した使用シナリオ</strong>：</p><ul><li>AI Agentがプランを完了し<code>ExitPlanMode</code>を呼び出した（Claude Code）</li><li>AI Agentが<code>submit_plan</code>ツールを呼び出した（OpenCode）</li><li>AI生成の実装プランをレビューする必要がある</li><li>プランの修正意見を正確にフィードバックする必要がある</li></ul><p><strong>適さないシナリオ</strong>：</p><ul><li>AIに直接コードを実装させる（プランレビューをスキップ）</li><li>すでにプランを承認済みで、実際のコード変更をレビューする必要がある（コードレビュー機能を使用）</li></ul><h2 id="🎒-始める前の準備" tabindex="-1">🎒 始める前の準備 <a class="header-anchor" href="#🎒-始める前の準備" aria-label="Permalink to &quot;🎒 始める前の準備&quot;">​</a></h2><p><strong>前提条件</strong>：</p><ul><li>✅ Plannotator CLIをインストール済み（詳細は<a href="./../../start/getting-started/">クイックスタート</a>を参照）</li><li>✅ Claude CodeまたはOpenCodeプラグインを設定済み（対応するインストールガイドを参照）</li><li>✅ AI Agentがプランレビューをサポート（Claude Code 2.1.7+、またはOpenCode）</li></ul><p><strong>トリガー方法</strong>：</p><ul><li><strong>Claude Code</strong>：AIがplanを完了後、自動的に<code>ExitPlanMode</code>を呼び出し、Plannotatorが自動起動</li><li><strong>OpenCode</strong>：AIが<code>submit_plan</code>ツールを呼び出し、Plannotatorが自動起動</li></ul><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><h3 id="プランレビューとは" tabindex="-1">プランレビューとは <a class="header-anchor" href="#プランレビューとは" aria-label="Permalink to &quot;プランレビューとは&quot;">​</a></h3><p><strong>プランレビュー</strong>はPlannotatorのコア機能で、AI生成の実装プランをビジュアルでレビューするために使用します。</p><div class="info custom-block"><p class="custom-block-title">なぜプランレビューが必要？</p><p>AIがプランを生成した後、通常「このプランでよろしいですか？」や「実装を開始しますか？」と尋ねます。ビジュアルツールがなければ、ターミナルでプレーンテキストのプランを読み、「OK」「ダメ、XXを修正して」などの曖昧なフィードバックを返すしかありません。Plannotatorを使えば、ビジュアルインターフェースでプランを確認し、修正が必要な部分を正確に選択して構造化アノテーションを追加でき、AIがあなたの意図をより理解しやすくなります。</p></div><h3 id="ワークフロー" tabindex="-1">ワークフロー <a class="header-anchor" href="#ワークフロー" aria-label="Permalink to &quot;ワークフロー&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (プラン生成)   │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ ExitPlanMode / submit_plan</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│ Plannotator UI  │  ← ブラウザが自動で開く</span></span>
<span class="line"><span>│                 │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ プラン内容  │  │</span></span>
<span class="line"><span>│ │ (Markdown) │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       │ テキストを選択</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ アノテーション │  │</span></span>
<span class="line"><span>│ │ 追加       │  │</span></span>
<span class="line"><span>│ │ Delete/    │  │</span></span>
<span class="line"><span>│ │ Replace/   │  │</span></span>
<span class="line"><span>│ │ Comment    │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ 決定      │  │</span></span>
<span class="line"><span>│ │ Approve/  │  │</span></span>
<span class="line"><span>│ │ Request   │  │</span></span>
<span class="line"><span>│ │ Changes   │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;allow&quot;} または</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (実装を続行)   │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h3 id="アノテーションタイプ" tabindex="-1">アノテーションタイプ <a class="header-anchor" href="#アノテーションタイプ" aria-label="Permalink to &quot;アノテーションタイプ&quot;">​</a></h3><p>Plannotatorは4種類のアノテーションタイ��をサポートしており、それぞれ異なる用途があります：</p><table tabindex="0"><thead><tr><th>アノテーションタイプ</th><th>用途</th><th>AIが受け取るフィードバック</th></tr></thead><tbody><tr><td><strong>Delete</strong></td><td>不要なコンテンツを削除</td><td>&quot;削除：[選択したテキスト]&quot;</td></tr><tr><td><strong>Replace</strong></td><td>より良いコンテンツに置換</td><td>&quot;置換：[選択したテキスト] を [入力したテキスト] に&quot;</td></tr><tr><td><strong>Comment</strong></td><td>特定の部分にコメント、修正は不要</td><td>&quot;コメント：[選択したテキスト]。説明：[入力したコメント]&quot;</td></tr><tr><td><strong>Global Comment</strong></td><td>グローバルコメント、特定のテキストに紐付けない</td><td>&quot;グローバルコメント：[入力したコメント]&quot;</td></tr></tbody></table><h3 id="approve-vs-request-changes" tabindex="-1">Approve vs Request Changes <a class="header-anchor" href="#approve-vs-request-changes" aria-label="Permalink to &quot;Approve vs Request Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>決定タイプ</th><th>操作</th><th>AIが受け取るフィードバック</th><th>適用シナリオ</th></tr></thead><tbody><tr><td><strong>Approve</strong></td><td>Approveボタンをクリック</td><td><code>{&quot;behavior&quot;: &quot;allow&quot;}</code></td><td>プランに問題なし、そのまま承認</td></tr><tr><td><strong>Request Changes</strong></td><td>Request Changesボタンをクリック</td><td><code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></td><td>修正が必要な箇所がある</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Claude CodeとOpenCodeの違い</p><ul><li><strong>Claude Code</strong>：Approve時にアノテーションは送信されない（アノテーションは無視される）</li><li><strong>OpenCode</strong>：Approve時にアノテーションを備考として送信可能（オプション）</li></ul><p><strong>プランを却下する場合</strong>：どちらのプラットフォームでも、アノテーションはAIに送信されます</p></div><h2 id="ステップバイステップ" tabindex="-1">ステップバイステップ <a class="header-anchor" href="#ステップバイステップ" aria-label="Permalink to &quot;ステップバイステップ&quot;">​</a></h2><h3 id="ステップ1-プランレビューをトリガー" tabindex="-1">ステップ1：プランレビューをトリガー <a class="header-anchor" href="#ステップ1-プランレビューをトリガー" aria-label="Permalink to &quot;ステップ1：プランレビューをトリガー&quot;">​</a></h3><p><strong>Claude Codeの例</strong>：</p><p>Claude CodeでAIと会話し、実装プランを生成させます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー：ユーザー認証モジュールの実装プランを作成してください</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude：はい、実装プランです：</span></span>
<span class="line"><span>1. ユーザーモデルを作成</span></span>
<span class="line"><span>2. 登録APIを実装</span></span>
<span class="line"><span>3. ログインAPIを実装</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>（AIがExitPlanModeを呼び出し）</span></span></code></pre></div><p><strong>OpenCodeの例</strong>：</p><p>OpenCodeでは、AIが自動的に<code>submit_plan</code>ツールを呼び出します。</p><p><strong>期待される結果</strong>：</p><ol><li>ブラウザが自動的にPlannotator UIを開く</li><li>AI生成のプラン内容が表示される（Markdown形式）</li><li>ページ下部に「Approve」と「Request Changes」ボタンがある</li></ol><h3 id="ステップ2-プラン内容を確認" tabindex="-1">ステップ2：プラン内容を確認 <a class="header-anchor" href="#ステップ2-プラン内容を確認" aria-label="Permalink to &quot;ステップ2：プラン内容を確認&quot;">​</a></h3><p>ブラウザでプランを確認します：</p><ul><li>プランはMarkdown形式でレンダリングされ、見出し、段落、リスト、コードブロックを含む</li><li>スクロールしてプラン全体を確認可能</li><li>ライト/ダークモードの切り替えをサポート（右上のテーマ切り替えボタンをクリック）</li></ul><h3 id="ステップ3-プランテキストを選択してアノテーションを追加" tabindex="-1">ステップ3：プランテキストを選択してアノテーションを追加 <a class="header-anchor" href="#ステップ3-プランテキストを選択してアノテーションを追加" aria-label="Permalink to &quot;ステップ3：プランテキストを選択してアノテーションを追加&quot;">​</a></h3><p><strong>Deleteアノテーションを追加</strong>：</p><ol><li>マウスでプラン内の削除したいテキストを選択</li><li>ポップアップツールバーで<strong>Delete</strong>ボタンをクリック</li><li>テキストが削除スタイル（赤い取り消し線）でマークされる</li></ol><p><strong>Replaceアノテーションを追加</strong>：</p><ol><li>マウスでプラン内の置換したいテキストを選択</li><li>ポップアップツールバーで<strong>Replace</strong>ボタンをクリック</li><li>ポップアップ入力欄に置換後のコンテンツを入力</li><li>Enterキーを押すか確認をクリック</li><li>元のテキストが置換スタイル（黄色の背景）でマークされ、下に置換内容が表示される</li></ol><p><strong>Commentアノテーションを追加</strong>：</p><ol><li>マウスでプラン内のコメントしたいテキストを選択</li><li>ポップアップツールバーで<strong>Comment</strong>ボタンをクリック</li><li>ポップアップ入力欄にコメント内容を入力</li><li>Enterキーを押すか確認をクリック</li><li>テキストがコメントスタイル（青いハイライト）でマークされ、サイドバーにコメントが表示される</li></ol><p><strong>Global Commentを追加</strong>：</p><ol><li>ページ右上の<strong>Add Global Comment</strong>ボタンをクリック</li><li>ポップアップ入力欄にグローバルコメント内容を入力</li><li>Enterキーを押すか確認をクリック</li><li>コメントがサイドバーの「Global Comments」セクションに表示される</li></ol><p><strong>期待される結果</strong>：</p><ul><li>テキストを選択すると、すぐにツールバー（Delete、Replace、Comment）がポップアップ</li><li>アノテーション追加後、テキストに対応するスタイル（取り消し線、背景色、ハイライト）が表示される</li><li>サイドバーにすべてのアノテーションリストが表示され、クリックで対応する位置にジャンプ可能</li><li>アノテーション横の<strong>削除</strong>ボタンをクリックしてアノテーションを削除可能</li></ul><h3 id="ステップ4-プランを承認" tabindex="-1">ステップ4：プランを承認 <a class="header-anchor" href="#ステップ4-プランを承認" aria-label="Permalink to &quot;ステップ4：プランを承認&quot;">​</a></h3><p><strong>プランに問題がない場合</strong>：</p><p>ページ下部の<strong>Approve</strong>ボタンをクリックします。</p><p><strong>期待される結果</strong>：</p><ul><li>ブラウザが自動的に閉じる（1.5秒の遅延）</li><li>Claude Code/OpenCodeのターミナルにプランが承認されたことが表示される</li><li>AIが実装を続行</li></ul><div class="info custom-block"><p class="custom-block-title">Approveの動作</p><ul><li><strong>Claude Code</strong>：<code>{&quot;behavior&quot;: &quot;allow&quot;}</code>のみ送信、アノテーションは無視される</li><li><strong>OpenCode</strong>：<code>{&quot;behavior&quot;: &quot;allow&quot;}</code>を送信、アノテーションは備考として送信可能（オプション）</li></ul></div><h3 id="ステップ5-プランを却下-request-changes" tabindex="-1">ステップ5：プランを却下（Request Changes） <a class="header-anchor" href="#ステップ5-プランを却下-request-changes" aria-label="Permalink to &quot;ステップ5：プランを却下（Request Changes）&quot;">​</a></h3><p><strong>プランに修正が必要な場合</strong>：</p><ol><li>必要なアノテーション（Delete、Replace、Comment）を追加</li><li>ページ下部の<strong>Request Changes</strong>ボタンをクリック</li><li>ブラウザに確認ダイアログが表示される</li></ol><p><strong>期待される結果</strong>：</p><ul><li>確認ダイアログに「Send X annotations to AI?」と表示される</li><li>確認をクリック後、ブラウザが自動的に閉じる</li><li>Claude Code/OpenCodeのターミナルにフィードバック内容が表示される</li><li>AIがフィードバックに基づいてプランを修正</li></ul><div class="tip custom-block"><p class="custom-block-title">Request Changesの動作</p><ul><li><strong>Claude Code</strong>と<strong>OpenCode</strong>：どちらも<code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code>を送信</li><li>アノテーションは構造化されたMarkdownテキストに変換される</li><li>AIがアノテーションに基づいてプランを修正し、再度ExitPlanMode/submit_planを呼び出す</li></ul></div><h3 id="ステップ6-フィードバック内容を確認-オプション" tabindex="-1">ステップ6：フィードバック内容を確認（オプション） <a class="header-anchor" href="#ステップ6-フィードバック内容を確認-オプション" aria-label="Permalink to &quot;ステップ6：フィードバック内容を確認（オプション）&quot;">​</a></h3><p>PlannotatorがAIに送信したフィードバック内容を確認したい場合は、ターミナルで確認できます：</p><p><strong>Claude Code</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan rejected by user</span></span>
<span class="line"><span>Please modify the plan based on the following feedback:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[構造化されたアノテーション内容]</span></span></code></pre></div><p><strong>OpenCode</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;feedback&gt;</span></span>
<span class="line"><span>[構造化されたアノテーション内容]</span></span>
<span class="line"><span>&lt;/feedback&gt;</span></span></code></pre></div><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>上記のステップを完了すると��以下ができるようになります：</p><ul><li>[ ] AIがプランレビューをトリガー後、ブラウザが自動的にPlannotator UIを開く</li><li>[ ] プランテキストを選択し、Delete、Replace、Commentアノテーションを追加</li><li>[ ] Global Commentを追加</li><li>[ ] サイドバーですべてのアノテーションを確認し、対応する位置にジャンプ</li><li>[ ] Approveをクリック、ブラウザが閉じ、AIが実装を続行</li><li>[ ] Request Changesをクリック、ブラウザが閉じ、AIがプランを修正</li></ul><p><strong>いずれかのステップで失敗した場合</strong>は、以下を参照：</p><ul><li><a href="./../../faq/common-problems/">よくある質問</a></li><li><a href="./../../start/installation-claude-code/">Claude Codeインストールガイド</a></li><li><a href="./../../start/installation-opencode/">OpenCodeインストールガイド</a></li></ul><h2 id="よくあるトラブル" tabindex="-1">よくあるトラブル <a class="header-anchor" href="#よくあるトラブル" aria-label="Permalink to &quot;よくあるトラブル&quot;">​</a></h2><p><strong>よくあるエラー1</strong>：テキストを選択してもツールバーがポップアップしない</p><p><strong>原因</strong>：コードブロック内のテキストを選択した、または複数の要素にまたがるテキストを選択した可能性があります。</p><p><strong>解決方法</strong>：</p><ul><li>単一の段落またはリスト項目内のテキストを選択するようにする</li><li>コードブロックの場合は、Commentアノテーションを使用し、複数行にまたがる選択を避ける</li></ul><p><strong>よくあるエラー2</strong>：Replaceアノテーションを追加後、置換内容が表示されない</p><p><strong>原因</strong>：置換内容の入力欄が正しく送信されていない可能性があります。</p><p><strong>解決方法</strong>：</p><ul><li>置換内容を入力後、Enterキーを押すか確認ボタンをクリック</li><li>サイドバーに置換内容が表示されているか確認</li></ul><p><strong>よくあるエラー3</strong>：ApproveまたはRequest Changesをクリック後、ブラウザが閉じない</p><p><strong>原因</strong>：サーバーエラーまたはネットワークの問題の可能性があります。</p><p><strong>解決方法</strong>：</p><ul><li>ターミナルにエラーメッセージがないか確認</li><li>手動でブラウザを閉じる</li><li>問題が続く場合は、<a href="./../../faq/troubleshooting/">トラブルシューティング</a>を参照</li></ul><p><strong>よくあるエラー4</strong>：AIがフィードバックを受け取った後、アノテーション通りに修正しない</p><p><strong>原因</strong>：AIがアノテーションの意図を正しく理解していない可能性があります。</p><p><strong>解決方法</strong>：</p><ul><li>より明確なアノテーションを使用する（ReplaceはCommentより明確）</li><li>Comment���使用して詳細な説明を追加</li><li>問題が続く場合は、再度プランを却下し、アノテーション内容を調整</li></ul><p><strong>よくあるエラー5</strong>：複数のDeleteアノテーションを追加後、AIが一部のコンテンツしか削除しない</p><p><strong>原因</strong>：複数のDeleteアノテーション間に重複や競合がある可能性があります。</p><p><strong>解決方法</strong>：</p><ul><li>各Deleteアノテーションのテキスト範囲が重複しないようにする</li><li>大きなセクションを削除する必要がある場合は、段落全体を一度に選択して削除</li></ul><h2 id="この章のまとめ" tabindex="-1">この章のまとめ <a class="header-anchor" href="#この章のまとめ" aria-label="Permalink to &quot;この章のまとめ&quot;">​</a></h2><p>プランレビューはPlannotatorのコア機能で、AI生成のプランをビジュアルでレビューできます：</p><p><strong>コア操作</strong>：</p><ol><li><strong>トリガー</strong>：AIが<code>ExitPlanMode</code>または<code>submit_plan</code>を呼び出し、ブラウザが自動的にUIを開く</li><li><strong>確認</strong>：ビジュアルインターフェースでプラン内容を確認（Markdown形式）</li><li><strong>アノテーション</strong>：テキストを選択し、Delete、Replace、CommentまたはGlobal Commentを追加</li><li><strong>決定</strong>：Approve（承認）またはRequest Changes（却下）をクリック</li><li><strong>フィードバック</strong>：アノテーションが構造化データに変換され、AIがフィードバックに基づいて続行または修正</li></ol><p><strong>アノテーションタイプ</strong>：</p><ul><li><strong>Delete</strong>：不要なコンテンツを削除</li><li><strong>Replace</strong>：より良いコンテンツに置換</li><li><strong>Comment</strong>：特定の部分にコメント、修正は不要</li><li><strong>Global Comment</strong>：グローバルコメント、特定のテキストに紐付けない</li></ul><p><strong>決定タイプ</strong>：</p><ul><li><strong>Approve</strong>：プランに問題なし、そのまま承認（Claude Codeはアノテーションを無視）</li><li><strong>Request Changes</strong>：修正が必要な箇所があり、アノテーションをAIに送信</li></ul><h2 id="次の章の予告" tabindex="-1">次の章の予告 <a class="header-anchor" href="#次の章の予告" aria-label="Permalink to &quot;次の章の予告&quot;">​</a></h2><blockquote><p>次の章では**<a href="./../plan-review-annotations/">プランアノテーションの追加</a>**を学びます。</p><p>学べる内容：</p><ul><li>Delete、Replace、Commentアノテーションの正確な使い方</li><li>画像アノテーションの追加方法</li><li>アノテーションの編集と削除方法</li><li>アノテーションのベストプラクティスとよくあるシナリオ</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>プランレビューUI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>アノテーションタイプ定義</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L1-L70" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>1-70</td></tr><tr><td>プランレビューサーバー</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L91-L310" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>91-310</td></tr><tr><td>API: プラン内容取得</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L132-L134" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>132-134</td></tr><tr><td>API: プラン承認</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L201-L277" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>201-277</td></tr><tr><td>API: プラン却下</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L280-L309" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>280-309</td></tr><tr><td>Viewerコンポーネント</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L1-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></td><td>1-100</td></tr><tr><td>AnnotationPanelコンポーネント</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a></td><td>1-50</td></tr></tbody></table><p><strong>主要な型</strong>：</p><ul><li><code>AnnotationType</code>：アノテーションタイプ列挙（DELETION、INSERTION、REPLACEMENT、COMMENT、GLOBAL_COMMENT）（<code>packages/ui/types.ts:1-7</code>）</li><li><code>Annotation</code>：アノテーションインターフェース（<code>packages/ui/types.ts:11-33</code>）</li><li><code>Block</code>：プランブロックインターフェース（<code>packages/ui/types.ts:35-44</code>）</li></ul><p><strong>主要な関数</strong>：</p><ul><li><code>startPlannotatorServer()</code>：プランレビューサーバーを起動（<code>packages/server/index.ts:91</code>）</li><li><code>parseMarkdownToBlocks()</code>：MarkdownをBlocksにパース（<code>packages/ui/utils/parser.ts</code>）</li></ul><p><strong>APIルート</strong>：</p><ul><li><code>GET /api/plan</code>：プラン内容を取得（<code>packages/server/index.ts:132</code>）</li><li><code>POST /api/approve</code>：プランを承認（<code>packages/server/index.ts:201</code>）</li><li><code>POST /api/deny</code>：プランを却下（<code>packages/server/index.ts:280</code>）</li></ul><p><strong>ビジネスルール</strong>：</p><ul><li>Claude Code承認時はアノテーションを送信しない（<code>apps/hook/server/index.ts:132</code>）</li><li>OpenCode承認時はアノテーションを備考として送信可能（<code>apps/opencode-plugin/index.ts:270</code>）</li><li>プラン却下時はアノテーションを常に送信（<code>apps/hook/server/index.ts:154</code>）</li></ul></details>`,112)])])}const h=n(o,[["render",l]]);export{u as __pageData,h as default};
